INSERT INTO Inquiry (
    user_id, inquiry_type, title, content
) VALUES (
    #{userId}, #{inquiryType}, #{title}, #{content}
)

mapper.select:
SELECT 
    inquiry_no AS inquiryNo,
    inquiry_type AS inquiryType,
    title,
    status,
    DATE_FORMAT(reg_date, '%Y-%m-%d') AS regDate
FROM Inquiry
WHERE user_id = #{userId}

    AND inquiry_type = #{searchType}


    AND status = #{searchStatus}

ORDER BY inquiry_no DESC
LIMIT #{startIndex}, #{pageSize}

SELECT COUNT(*) FROM Inquiry
WHERE user_id = #{userId}

    AND inquiry_type = #{searchType}


    AND status = #{searchStatus}
